+        let out_labels: Vec<_> = labels[start_pos..=end_pos].to_vec();
+        let out_values: Vec<_> = self.column.values()[start_pos..=end_pos].to_vec();
+
+        Self::from_values(self.name.clone(), out_labels, out_values)
+    }
